python3 << 'EOF'
"""
Adversarial test of the fix. Verify:
1. Guard keys match the right fields
2. gate_coordinator_node stores rationale
3. Changed unmet-prereq set still records event
4. gate_status refresh still returned
5. Type annotation correct
"""

# Simulate the exact code
from typing import Any

class MockState(dict):
    def __getitem__(self, key):
        if key == "run_id":
            return "test-run"
        return super().__getitem__(key)

def simulate_gate_2_logic(state, hard_failures):
    """Simulate gate_2_node when hard_failures exist."""
    rationale = "Hard prerequisite failure: " + "; ".join(hard_failures)

    # Guard condition
    prior = state.get("gate_status", {}).get("gate_2") or {}
    already_recorded = (
        prior.get("decision") == "deferred" and prior.get("rationale") == rationale
    )

    # Start with empty update dict
    update: dict[str, Any] = {}

    # Conditionally add failure_events
    if not already_recorded:
        update["failure_events"] = [{
            "event_type": "gate_prerequisite_failure",
            "gate_id": "gate_2",
            "failures": hard_failures,
            "run_id": state["run_id"],
            "timestamp_utc": "2026-06-15T00:00:00Z",
        }]

    # Always update with gate_coordinator result
    coordinator_result = {
        "gate_status": {
            "gate_2": {
                "gate_id": "gate_2",
                "decision": "deferred",
                "rationale": rationale,
                "reviewer": "system",
                "timestamp_utc": "2026-06-15T00:00:00Z",
                "run_id": state["run_id"],
            }
        }
    }
    update.update(coordinator_result)

    return update


# Test 1: First time - should append failure_events AND have gate_status
print("Test 1: First encounter with prereq failure")
state1 = {}
result1 = simulate_gate_2_logic(state1, ["data_split_verified is False"])
print(f"  Has failure_events: {'failure_events' in result1}")
print(f"  Has gate_status: {'gate_status' in result1}")
print(f"  gate_status refreshed: {result1.get('gate_status', {}).get('gate_2', {}).get('decision') == 'deferred'}")
assert 'failure_events' in result1, "FAIL: Should have failure_events"
assert 'gate_status' in result1, "FAIL: Should have gate_status"
print("  PASS\n")

# Test 2: Re-entry with same prereq - should NOT append, but SHOULD update gate_status
print("Test 2: Re-entry with same unmet prereq")
state2 = {
    "gate_status": {
        "gate_2": {
            "decision": "deferred",
            "rationale": "Hard prerequisite failure: data_split_verified is False"
        }
    }
}
result2 = simulate_gate_2_logic(state2, ["data_split_verified is False"])
print(f"  Has failure_events: {'failure_events' in result2}")
print(f"  Has gate_status: {'gate_status' in result2}")
print(f"  gate_status refreshed: {result2.get('gate_status', {}).get('gate_2', {}).get('decision') == 'deferred'}")
assert 'failure_events' not in result2, "FAIL: Should NOT have failure_events"
assert 'gate_status' in result2, "FAIL: Should STILL have gate_status"
print("  PASS\n")

# Test 3: Different prereq failure (more strict) - should append new event
print("Test 3: Different unmet prereq (exploratory_complete also failed)")
state3 = {
    "gate_status": {
        "gate_2": {
            "decision": "deferred",
            "rationale": "Hard prerequisite failure: data_split_verified is False"
        }
    }
}
result3 = simulate_gate_2_logic(state3, ["data_split_verified is False", "exploratory_complete is False"])
print(f"  Has failure_events: {'failure_events' in result3}")
print(f"  Has gate_status: {'gate_status' in result3}")
print(f"  gate_status refreshed: {result3.get('gate_status', {}).get('gate_2', {}).get('decision') == 'deferred'}")
assert 'failure_events' in result3, "FAIL: Should have failure_events (different prereq)"
assert 'gate_status' in result3, "FAIL: Should have gate_status"
print("  PASS\n")

# Test 4: Non-deferred prior decision - should append
print("Test 4: Prior decision is 'approved', not 'deferred'")
state4 = {
    "gate_status": {
        "gate_2": {
            "decision": "approved",
            "rationale": "Previously approved"
        }
    }
}
result4 = simulate_gate_2_logic(state4, ["data_split_verified is False"])
print(f"  Has failure_events: {'failure_events' in result4}")
print(f"  Has gate_status: {'gate_status' in result4}")
assert 'failure_events' in result4, "FAIL: Should have failure_events (different decision type)"
assert 'gate_status' in result4, "FAIL: Should have gate_status"
print("  PASS\n")

print("=== All adversarial tests passed ===")
EOF

